/* ---------- cancel confirmation modal ---------- */

function CancelModal({ open, loading, onConfirm, onRetentionAccept, onClose, currentTier }) {
  const [step, setStep] = useState('save'); // 'save' | 'retention' | 'confirm'

  useEffect(() => { if (open) setStep('save'); }, [open]);

  if (!open) return null;

  const tierKey = (currentTier || '').toLowerCase();
  const features = TIER_FEATURES[tierKey];
  const downgradeTo = DOWNGRADE_MAP[tierKey];
  const downgradeFeatures = downgradeTo ? TIER_FEATURES[downgradeTo] : null;
  const downgradeLabel = downgradeTo ? downgradeTo.replace(/_/g, ' ').replace(/\b\w/g, c => c.toUpperCase()) : null;

  const lossItems = features ? [
    `${features.bots} live trading bot${features.bots !== 1 ? 's' : ''}`,
    `${features.strategies} strategies`,
    `${features.regions} market${features.regions === 'US' ? '' : 's'}`,
    `${features.ai} AI tokens/mo`,
    features.compute !== '0 hrs' ? `${features.compute} cloud compute/mo` : null,
  ].filter(Boolean) : [];

  return (
    <div onClick={onClose} className={s.modalOverlay}>
      <div onClick={(e) => e.stopPropagation()} className={s.modalContent}>
        {step === 'save' ? (
          <>
            <div className={s.modalTitle}>We're sorry to see you go</div>
            <p className={s.modalDesc}>
              If you cancel, you'll lose access to:
            </p>

            {/* Loss items */}
            <div className={s.lossBox} style={{
              background: `${C.red}08`, border: `1px solid ${C.red}20`,
            }}>
              {lossItems.map((item, i) => (
                <div key={i} className={s.lossItem}>
                  <span className={s.lossX}>&#10005;</span>
                  {item}
                </div>
              ))}
            </div>

            {/* Downgrade offer */}
            {downgradeTo && downgradeFeatures && (
              <div className={s.downgradeBox} style={{
                background: `${C.blue}08`, border: `1px solid ${C.blue}25`,
              }}>
                <div className={s.downgradeTitle}>
                  Instead, downgrade to {downgradeLabel}?
                </div>
                <div className={s.downgradeDesc}>
                  Keep trading at <span className={s.downgradePrice}>${downgradeFeatures.price}/mo</span> with
                  {' '}{downgradeFeatures.bots} bot{downgradeFeatures.bots !== 1 ? 's' : ''}, {downgradeFeatures.ai} AI tokens,
                  and {downgradeFeatures.compute} compute.
                </div>
                <a href="/pricing" className={s.downgradeBtn}>
                  Switch to {downgradeLabel}
                </a>
              </div>
            )}

            <div className={s.modalActions}>
              <button onClick={onClose} className={s.keepBtn}>
                Keep My Plan
              </button>
              <button onClick={() => setStep('retention')} className={s.continueBtn}>
                Continue cancellation
              </button>
            </div>
          </>
        ) : step === 'retention' ? (
          <>
            <div className={s.modalTitle}>Wait -- special offer just for you</div>
            <div className={s.retentionOffer}>
              <div className={s.retentionBadge}>EXCLUSIVE</div>
              <div className={s.retentionHeadline}>Get 50% off for 3 months</div>
              <div className={s.retentionDesc}>
                Stay on your current plan at half price. That's just{' '}
                <span className={s.retentionPrice}>
                  ${features ? Math.round(features.price / 2) : '??'}/mo
                </span>{' '}
                for the next 3 billing cycles.
              </div>
              <button onClick={() => { onRetentionAccept?.(); onClose(); }} className={s.retentionAcceptBtn}>
                Accept 50% Off
              </button>
            </div>
            <div className={s.modalActions}>
              <button onClick={onClose} className={s.keepBtn}>
                Keep My Plan
              </button>
              <button onClick={() => setStep('confirm')} className={s.continueBtn}>
                No thanks, cancel
              </button>
            </div>
          </>
        ) : (
          <>
            <div className={s.modalTitleLg}>Confirm Cancellation</div>
            <p className={s.modalDescLg}>
              Your subscription will remain active until the end of your current billing period.
              You can resubscribe anytime to restore access.
            </p>
            <div className={s.modalActions}>
              <button onClick={() => { setStep('save'); onClose(); }} className={s.goBackBtn}>
                Go Back
              </button>
              <button
                onClick={() => { onConfirm(); setStep('save'); }}
                disabled={loading}
                className={s.confirmCancelBtn}
              >
                {loading ? 'Cancelling...' : 'Yes, Cancel Subscription'}
              </button>
            </div>
          </>
        )}
      </div>
    </div>
  );
}

/* ---------- upgrade/downgrade confirmation modal ---------- */

function PlanChangeModal({ open, targetPlan, currentPlan, onConfirm, onClose, loading }) {
  if (!open || !targetPlan) return null;

  const currentPrice = currentPlan?.price ?? 0;
  const targetPrice = targetPlan.price ?? 0;
  const isUpgrade = targetPrice > currentPrice;
  const priceDiff = Math.abs(targetPrice - currentPrice);
  const prorationEstimate = isUpgrade
    ? `You'll be charged approximately $${priceDiff.toFixed(2)} prorated for the remainder of this billing cycle.`
    : `Your next invoice will be reduced by approximately $${priceDiff.toFixed(2)}. The change takes effect at the next billing cycle.`;

  return (
    <div onClick={onClose} className={s.modalOverlay}>
      <div onClick={(e) => e.stopPropagation()} className={s.modalContent}>
        <div className={s.modalTitle}>
          {isUpgrade ? 'Upgrade' : 'Downgrade'} to {targetPlan.name}
        </div>

        <div className={s.planChangeCompare}>
          <div className={s.planChangeFrom}>
            <div className={s.planChangeLabel}>Current</div>
            <div className={s.planChangeTier}>{currentPlan?.name || 'Free'}</div>
            <div className={s.planChangePrice}>${currentPrice}/mo</div>
          </div>
          <div className={s.planChangeArrow}>{isUpgrade ? '\u2192' : '\u2193'}</div>
          <div className={s.planChangeTo}>
            <div className={s.planChangeLabel}>New Plan</div>
            <div className={s.planChangeTier} style={{ color: tierColor(targetPlan.key) }}>
              {targetPlan.name}
            </div>
            <div className={s.planChangePrice}>${targetPrice}/mo</div>
          </div>
        </div>

        <div className={s.prorationNotice}>
          {prorationEstimate}
        </div>

        <div className={s.modalActions}>
          <button onClick={onClose} className={s.goBackBtn}>Cancel</button>
          <button
            onClick={() => onConfirm(targetPlan.key)}
            disabled={loading}
            className={isUpgrade ? s.upgradeConfirmBtn : s.downgradeConfirmBtn}
          >
            {loading ? 'Processing...' : `Confirm ${isUpgrade ? 'Upgrade' : 'Downgrade'}`}
          </button>
        </div>
      </div>
    </div>
  );
}

