function StatusBadge({ status }) {
  const colorMap = {
    active: C.green, trialing: C.amber, trial: C.amber, paid: C.green,
    succeeded: C.green, open: C.blue, pending: C.amber,
    canceled: C.red, cancelled: C.red, past_due: C.red,
    failed: C.red, void: C.textSecondary, draft: C.textSecondary,
  };
  const color = colorMap[(status || '').toLowerCase()] || C.textSecondary;
  return (
    <span className={s.statusBadge} style={{ background: color }}>
      {status || 'unknown'}
    </span>
  );
}

function UsageBar({ label, current, max, formatFn }) {
  const pct = usagePct(current, max);
  const color = barColor(pct);
  const displayCurrent = formatFn ? formatFn(current) : current;
  const displayMax = formatFn ? formatFn(max) : max;
  return (
    <div className={s.usageBarWrap}>
      <div className={s.usageBarHeader}>
        <span className={s.usageBarLabel}>{label}</span>
        <span className={s.usageBarValue}>
          {displayCurrent} / {max === -1 ? '\u221E' : displayMax}
        </span>
      </div>
      <div className={s.usageBarTrack}>
        <div className={s.usageBarFill} style={{ width: `${pct}%`, background: color }} />
      </div>
    </div>
  );
}

